function formatAdditional(additional) {
    switch (additional.additionalType) {
        case AdditionalType.Default:
        case AdditionalType.PerProduct: {
            return { title: additional.details };
        }
        case AdditionalType.PerInformativePeople:
        case AdditionalType.PerPeople:
            return { title: `${additional.details}`, subTitle: 'Per person' };
        case AdditionalType.PerInformativeAdult:
        case AdditionalType.PerAdult:
            return { title: `${additional.details}`, subTitle: 'Per adult' };
        case AdditionalType.PerInformativeChildren:
        case AdditionalType.PerChildren:
            return { title: `${additional.details}`, subTitle: 'Per child' };
        case AdditionalType.PerInfant:
            return { title: `${additional.details}`, subTitle: 'Per infant' };
        case AdditionalType.PerUnit: {
            return { title: `${additional.details} ` };
        }
    }
}

function formatMoney(value, options = {}) {
    const { currency, maxDecimals = 2, showDecimals = false, compact = false, } = options;
    const decimals = showDecimals || value % 1 !== 0 ? maxDecimals : 0;
    const formatter = new Intl.NumberFormat('en-US', {
        style: 'currency',
        currency: currency || 'USD',
        minimumFractionDigits: decimals,
        maximumFractionDigits: decimals,
        notation: compact ? 'compact' : undefined,
    });
    return formatter.format(value);
}

